def compute_score() -> tuple[str, float]:
    from pptx import Presentation

    correct_old_text = "AIRCRAFT SURFACE"
    correct_new_text = "AIRCRAFT FUNDAMENTALS"

    prs_original = Presentation(original_ppt_path)
    prs_modified = Presentation(modified_ppt_path)

    def get_title_text(prs, slide_idx):
        slide = prs.slides[slide_idx]
        for shape in slide.shapes:
            if shape.has_text_frame and shape.text_frame is not None:
                if shape.text_frame.text.strip().upper() == correct_old_text or \
                   shape.text_frame.text.strip().upper() == correct_new_text:
                    return shape.text_frame.text.strip().upper()
        # fallback: grab the first shape that seems to be title
        for shape in slide.shapes:
            if shape.name.lower().startswith("title") and shape.has_text_frame:
                return shape.text_frame.text.strip().upper()
        return None

    orig_title = get_title_text(prs_original, 0)  # slide 1 is index 0
    mod_title = get_title_text(prs_modified, 0)

    if orig_title != correct_old_text:
        return (f"Original slide 1 title was not '{correct_old_text}', found '{orig_title}'.", 0.0)

    if mod_title == correct_new_text:
        return ("Slide 1 title correctly changed to 'AIRCRAFT FUNDAMENTALS'", 1.0)
    else:
        return (f"Slide 1 title was not correctly changed. Found '{mod_title}'.", 0.0)

def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    # Check shapes (slides), for slide 1
    prs_orig = Presentation(original_ppt_path)
    prs_mod = Presentation(modified_ppt_path)
    orig_slide = prs_orig.slides[0]
    mod_slide = prs_mod.slides[0]
    # Compare all shapes except for the title
    def get_shape_texts(slide):
        txts = []
        for shape in slide.shapes:
            if shape.has_text_frame and shape.text_frame is not None:
                txts.append((shape.name, shape.text_frame.text.strip()))
        return txts

    orig_texts = get_shape_texts(orig_slide)
    mod_texts = get_shape_texts(mod_slide)
    # Get change set:
    changed = []
    for (n1,t1), (n2,t2) in zip(orig_texts, mod_texts):
        # If the names match and it's title, skip it (expected to change)
        if (n1.lower().startswith("title") or t1.upper()=="AIRCRAFT SURFACE") and (n2.lower().startswith("title") or t2.upper()=="AIRCRAFT FUNDAMENTALS"):
            continue
        if t1 != t2:
            changed.append((n1, t1, t2))
    # Also check number of shapes/elements
    if len(orig_slide.shapes) != len(mod_slide.shapes):
        return (f"Shape count changed on slide 1 (from {len(orig_slide.shapes)} to {len(mod_slide.shapes)})", 0.0)
    if changed:
        return (f"Text or content changed on one or more non-title elements of slide 1: {changed}", 0.0)
    return ("No unintended changes on slide 1", 1.0)

def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    prs_orig = Presentation(original_ppt_path)
    prs_mod = Presentation(modified_ppt_path)
    if len(prs_orig.slides) != len(prs_mod.slides):
        return (f"Total number of slides changed from {len(prs_orig.slides)} to {len(prs_mod.slides)}", 0.0)
    # Compare slide content for all slides except slide 1
    for idx in range(1, len(prs_orig.slides)):
        orig_slide = prs_orig.slides[idx]
        mod_slide = prs_mod.slides[idx]
        # Compare text content
        orig_texts = [s.text_frame.text.strip() for s in orig_slide.shapes if s.has_text_frame and s.text_frame is not None]
        mod_texts = [s.text_frame.text.strip() for s in mod_slide.shapes if s.has_text_frame and s.text_frame is not None]
        if orig_texts != mod_texts:
            return (f"Content changed on slide {idx+1} other than slide 1.", 0.0)
    return ("No changes to other slides detected", 1.0)

